    JSON.stringify(createErrorResponse(error, details)),
    {
      status,
      headers: {
        ...corsHeaders,
        'Content-Type': 'application/json',
      },
    }
  )
}

// F-001 · Cliente ReceitaWS para consulta Simples Nacional (ADR-002).
// Helper isolado consumido por `create-cliente-v2` e `tiny-enviar-pedido-venda-v1`.
//
// Schemas espelham `packages/shared/types/simples-nacional.ts` (Zod + TS).
// Como Edge Functions Deno hoje não importam zod diretamente, aqui reproduzimos
// os shapes como `type` — fonte de verdade continua sendo os schemas Zod.

const RECEITAWS_BASE_URL = "https://www.receitaws.com.br/v1/cnpj";
const DEFAULT_TIMEOUT_MS = 5_000;

export type LookupOutcome =
  | "ok"
  | "missing_field"
  | "timeout"
  | "rate_limited"
  | "invalid_response"
  | "network_error";

export interface SimplesNacionalLookupResult {
  status: "ok" | "inconclusive" | "failed";
  optante: boolean | null;
  reason: LookupOutcome | null;
  consultadoEm: string;
}

export interface SimplesNacionalLookupLog {
  event: "receitaws.lookup";
  traceId: string;
  cnpjMasked: string;
  httpStatus: number | null;
  simplesOptante: boolean | null;
  durationMs: number;
  outcome: LookupOutcome;
}

/**
 * Mascara CNPJ preservando apenas os 3 primeiros dígitos + "*" + 2 últimos.
 * Ver SPEC RNF-003 (NÃO logar CNPJ completo em texto claro).
 */
export function maskCnpj(cnpj: string): string {
  const digits = (cnpj || "").replace(/\D/g, "");
  if (digits.length < 5) return "***";
  return `${digits.slice(0, 3)}*****${digits.slice(-2)}`;
}

function nowIso(): string {
  return new Date().toISOString();
}

function emitLog(log: SimplesNacionalLookupLog): void {
  // Log estruturado único ponto — aderente ao padrão das Edge Functions -v2.
  console.log(JSON.stringify(log));
}

const RATE_LIMIT_RETRY_DELAY_MS = 3_000;

/**
 * Consulta ReceitaWS pelo CNPJ e devolve um resultado normalizado pronto para
 * persistir no cliente.
 *
 * - Timeout 5s (AbortController) — DP-002 resolvida 2026-04-22.
 * - Token opcional via `RECEITAWS_TOKEN` (ADR-002):
 *     ausente → API Pública (3 req/min nominais, ~1 req/s na prática);
 *     presente → API Comercial (Bearer no header Authorization).
 *   No MVP F-001 operamos sem token — o helper segue chamando a API Pública.
 * - **INC-004 (rate limit recovery)**: ao receber HTTP 429, espera
 *   `RATE_LIMIT_RETRY_DELAY_MS` e tenta UMA vez mais. Mitiga o cenário em que
 *   o primeiro envio de pedido para um cliente ainda não consultado bate em
 *   janela de rate limit e cai com `optanteSimples=null` no resolver.
 * - Resposta bruta NUNCA persistida (Anti-SPEC §6).
 * - `simples.optante` ausente → status `inconclusive` com reason `missing_field`
 *   (CB-001 · plano gratuito não retorna o objeto `simples`).
 */
export async function consultarSimplesNacional(params: {
  cnpj: string;
  traceId: string;
  timeoutMs?: number;
}): Promise<SimplesNacionalLookupResult> {
  const first = await attemptLookup(params, 1);
  if (first.status === "failed" && first.reason === "rate_limited") {
    await new Promise((r) => setTimeout(r, RATE_LIMIT_RETRY_DELAY_MS));
    return attemptLookup(params, 2);
  }
  return first;
}

async function attemptLookup(
  params: {
    cnpj: string;
    traceId: string;
    timeoutMs?: number;
  },
  attempt: 1 | 2,
): Promise<SimplesNacionalLookupResult> {
  const { cnpj, traceId } = params;
  const timeoutMs = params.timeoutMs ?? DEFAULT_TIMEOUT_MS;
  const cnpjMasked = maskCnpj(cnpj);
  const start = Date.now();
  const digits = (cnpj || "").replace(/\D/g, "");
  // attempt is exposed via traceId suffix in logs to distinguish retries.
  const traceIdAttempt = attempt === 1 ? traceId : `${traceId}/retry`;

  if (digits.length !== 14) {
    const durationMs = Date.now() - start;
    emitLog({
      event: "receitaws.lookup",
      traceId: traceIdAttempt,
      cnpjMasked,
      httpStatus: null,
      simplesOptante: null,
      durationMs,
      outcome: "invalid_response",
    });
    return {
      status: "failed",
      optante: null,
      reason: "invalid_response",
      consultadoEm: nowIso(),
    };
  }

  const token = (Deno.env.get("RECEITAWS_TOKEN") || "").trim();

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const url = `${RECEITAWS_BASE_URL}/${digits}`;
    const headers: Record<string, string> = {
      Accept: "application/json",
    };
    if (token) {
      headers["Authorization"] = `Bearer ${token}`;
    }
    const res = await fetch(url, {
      method: "GET",
      headers,
      signal: controller.signal,
    });

    const durationMs = Date.now() - start;

    if (res.status === 429) {
      emitLog({
        event: "receitaws.lookup",
        traceId,
        cnpjMasked,
        httpStatus: 429,
        simplesOptante: null,
        durationMs,
        outcome: "rate_limited",
      });
      return {
        status: "failed",
        optante: null,
        reason: "rate_limited",
        consultadoEm: nowIso(),
      };
    }

    if (!res.ok) {
      emitLog({
        event: "receitaws.lookup",
        traceId,
        cnpjMasked,
        httpStatus: res.status,
        simplesOptante: null,
        durationMs,
        outcome: "invalid_response",
      });
      return {
        status: "failed",
        optante: null,
        reason: "invalid_response",
        consultadoEm: nowIso(),
      };
    }

    // INC-005: ReceitaWS retorna rate-limit em formatos NÃO documentados:
    //   (a) HTTP 429 (caso oficial — tratado acima)
    //   (b) HTTP 200 com body em TEXTO PLANO "Too many requests, please try again later."
    //       (observado em produção em 30/abr/2026 — passava a aparecer como
    //       invalid_response e o retry de rate_limited não disparava, e o
    //       fallback escolhia tinyValor padrão mesmo para cliente Simples)
    // Lemos o body como texto e depois decidimos. Se for texto com "Too many",
    // tratamos como rate_limited e o wrapper fará o retry com backoff.
    const rawBody = await res.text();
    const lowerSnippet = rawBody.slice(0, 256).toLowerCase();
    const looksRateLimited =
      lowerSnippet.includes("too many requests") ||
      lowerSnippet.includes("muitas requisi") ||
      (lowerSnippet.includes("limite") && lowerSnippet.includes("excedido"));
    if (looksRateLimited) {
      emitLog({
        event: "receitaws.lookup",
        traceId: traceIdAttempt,
        cnpjMasked,
        httpStatus: res.status,
        simplesOptante: null,
        durationMs,
        outcome: "rate_limited",
      });
      return {
        status: "failed",
        optante: null,
        reason: "rate_limited",
        consultadoEm: nowIso(),
      };
    }

    let body: unknown = null;
    try {
      body = JSON.parse(rawBody);
    } catch {
      emitLog({
        event: "receitaws.lookup",
        traceId,
        cnpjMasked,
        httpStatus: res.status,
        simplesOptante: null,
        durationMs,
        outcome: "invalid_response",
      });
      return {
        status: "failed",
        optante: null,
        reason: "invalid_response",
        consultadoEm: nowIso(),
      };
    }

    const simples =
      body && typeof body === "object" && "simples" in body
        ? (body as { simples?: { optante?: unknown } }).simples
        : undefined;
    const optanteRaw = simples?.optante;

    if (typeof optanteRaw !== "boolean") {
      emitLog({
        event: "receitaws.lookup",
        traceId,
        cnpjMasked,
        httpStatus: res.status,
        simplesOptante: null,
        durationMs,
        outcome: "missing_field",
      });
      return {
        status: "inconclusive",
        optante: null,
        reason: "missing_field",
        consultadoEm: nowIso(),
      };
    }

    emitLog({
      event: "receitaws.lookup",
      traceId: traceIdAttempt,
      cnpjMasked,
      httpStatus: res.status,
      simplesOptante: optanteRaw,
      durationMs,
      outcome: "ok",
    });
    return {
      status: "ok",
      optante: optanteRaw,
      reason: null,
      consultadoEm: nowIso(),
    };
  } catch (err) {
    const durationMs = Date.now() - start;
    const isAbort = err instanceof Error && err.name === "AbortError";
    const outcome: LookupOutcome = isAbort ? "timeout" : "network_error";
    emitLog({
      event: "receitaws.lookup",
      traceId: traceIdAttempt,
      cnpjMasked,
      httpStatus: null,
      simplesOptante: null,
      durationMs,
      outcome,
    });
    return {
      status: "failed",
      optante: null,
      reason: outcome,
      consultadoEm: nowIso(),
    };
  } finally {
    clearTimeout(timer);
  }
}

// F-001 · Helper puro para resolver qual `tiny_valor` usar ao enviar pedido Tiny.
// Consumido por `tiny-enviar-pedido-venda-v1` (Deno Edge Function) e pelos
// smoke tests em `tests/edge/simples-nacional.test.ts`.
//
// Fonte de verdade dos tipos: `packages/shared/types/natureza-operacao.ts`.
// O helper aceita um subset estrutural (NaturezaMapeamento) para permanecer
// trivialmente testável sem importar zod do runtime Deno.

export type FallbackUsed =
  | "none"
  | "no_dual"
  | "no_dual_company"
  | "null_optante"
  | "revalidation_failed";

export interface NaturezaMapeamento {
  tinyValor: string;
  tinyValorSimples: string | null;
}

export interface ResolveNaturezaParams {
  mapeamento: NaturezaMapeamento;
  optanteSimples: boolean | null;
  /**
   * DP-006 (2026-04-24): quando `false`, a empresa inteira não possui nenhum
   * mapeamento ativo com `tiny_valor_simples` preenchido — o caller já
   * evitou a consulta ReceitaWS, e aqui apenas retornamos `tinyValor` com
   * fallback `no_dual_company` para registrar a razão no log.
   * Default (ausente ou `true`): comportamento pré-DP-006 (avalia per-row).
   */
  companyHasDualMapping?: boolean;
}

export interface ResolveNaturezaResult {
  tinyValor: string;
  fallbackUsed: FallbackUsed;
}

/**
 * Escolhe `tiny_valor` para o payload Tiny aplicando as regras de F-001 (CA-007):
 *  - DP-006: `companyHasDualMapping === false` → `tinyValor`, fallback "no_dual_company".
 *  - Mapeamento sem dual (`tinyValorSimples` null/vazio) → usa `tinyValor`, fallback "no_dual".
 *  - Mapeamento com dual e `optanteSimples === null` → usa `tinyValor`, fallback "null_optante".
 *  - Mapeamento com dual e `optanteSimples === true` → usa `tinyValorSimples`, fallback "none".
 *  - Mapeamento com dual e `optanteSimples === false` → usa `tinyValor`, fallback "none".
 *
 * Função 100% pura: sem I/O, sem logging, sem exceptions. O caller (a Edge
 * Function) é quem constrói o evento `natureza.resolvida` conforme o schema
 * `NaturezaOperacaoResolucao` em `packages/shared/types/natureza-operacao.ts`
 * usando `traceId`, `empresaId`, `naturezaOperacaoId` + este resultado.
 */
export function resolveNaturezaTiny(
  params: ResolveNaturezaParams,
): ResolveNaturezaResult {
  const { mapeamento, optanteSimples, companyHasDualMapping } = params;

  // DP-006 · Short-circuit: empresa inteira sem dual-ID. Precede regras
  // per-row porque, se a empresa não tem NENHUM mapeamento com Simples,
  // o log deve indicar a razão empresa-level (e não row-level).
  if (companyHasDualMapping === false) {
    return { tinyValor: mapeamento.tinyValor, fallbackUsed: "no_dual_company" };
  }

  const tinyValorSimples =
    mapeamento.tinyValorSimples === null ||
    mapeamento.tinyValorSimples === ""
      ? null
      : mapeamento.tinyValorSimples;

  if (tinyValorSimples === null) {
    return { tinyValor: mapeamento.tinyValor, fallbackUsed: "no_dual" };
  }

  if (optanteSimples === null) {
    return { tinyValor: mapeamento.tinyValor, fallbackUsed: "null_optante" };
  }

  if (optanteSimples === true) {
    return { tinyValor: tinyValorSimples, fallbackUsed: "none" };
  }

  return { tinyValor: mapeamento.tinyValor, fallbackUsed: "none" };
}

// BUG-001 · Edge Functions Deno rodam com TZ default UTC. `new Date().toISOString()`
// (e os métodos `getDate/getMonth/getFullYear` em runtime UTC) devolviam o dia
// UTC, o que estoura para D+1 entre 21h-23h59 BRT. O Tiny exibia a data UTC
// sem reconverter para America/Sao_Paulo.
//
// Esta função usa `Intl.DateTimeFormat` com `timeZone: America/Sao_Paulo` para
// extrair os componentes da data já no fuso brasileiro.

export function formatDateBR(date: Date): string {
  const parts = new Intl.DateTimeFormat("pt-BR", {
    timeZone: "America/Sao_Paulo",
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  }).formatToParts(date);
  const get = (type: string) =>
    parts.find((p) => p.type === type)?.value ?? "";
  return `${get("day")}/${get("month")}/${get("year")}`;
}
